```rust
fn send_form_data(name: String, email: String) -> Result<(), reqwest::Error> {
  let url = "https://api.example.com/form";
  let client = reqwest::blocking::Client::new();
  let json = serde_json::json!({
    "name": name,
    "email": email
  });
  client.post(url)
     .json(&json)
     .send()?
     .error_for_status()
}
```
